import{_ as i,o as t,c as r,ae as a}from"./chunks/framework.Czhw_PXq.js";const d=JSON.parse('{"title":"股市趋势技术分析圣经 - 第6章：缺口理论","description":"系统讲解普通缺口、突破缺口、整理缺口和竭尽缺口的识别方法、技术含义与实战应用","frontmatter":{"title":"股市趋势技术分析圣经 - 第6章：缺口理论","description":"系统讲解普通缺口、突破缺口、整理缺口和竭尽缺口的识别方法、技术含义与实战应用","date":"2026-04-18","author":"技术分析研习社","tags":["缺口理论","突破缺口","竭尽缺口","岛形反转","技术分析"],"category":"技术分析","cover":"/images/sta/chapter6-cover.jpg"},"headers":[],"relativePath":"posts/sta-chapter-6.md","filePath":"posts/sta-chapter-6.md"}'),o={name:"posts/sta-chapter-6.md"};function n(s,l,e,u,p,g){return t(),r("div",null,[...l[0]||(l[0]=[a('<h1 id="第6章-缺口理论" tabindex="-1">第6章：缺口理论 <a class="header-anchor" href="#第6章-缺口理论" aria-label="Permalink to &quot;第6章：缺口理论&quot;">​</a></h1><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>在股票价格走势图中，我们经常会看到连续两天的价格线之间存在&quot;空当&quot;——这就是<strong>缺口（Gap）</strong>。缺口是技术分析中一个既有趣又有迷惑性的现象，许多投资者对其寄予厚望，认为它具有重要的预测意义。</p><p>理查德·W·夏巴克在本章中指出：&quot;针对股价缺口的理论研究已经是百家争鸣，而且各家都声称自己的理论具有重要的预测意义。&quot;但同时他也提醒我们：&quot;缺口确实在技术预测中占据一席之地，但是它的价值主要在于对其他图表预测的确认或修正。&quot;</p><p>本章将系统介绍缺口的四种分类、识别方法和实战应用，帮助读者正确理解和使用这一技术工具。</p><h2 id="一、缺口的基本概念" tabindex="-1">一、缺口的基本概念 <a class="header-anchor" href="#一、缺口的基本概念" aria-label="Permalink to &quot;一、缺口的基本概念&quot;">​</a></h2><h3 id="_1-1-什么是缺口" tabindex="-1">1.1 什么是缺口？ <a class="header-anchor" href="#_1-1-什么是缺口" aria-label="Permalink to &quot;1.1 什么是缺口？&quot;">​</a></h3><p>缺口指股票图中连续两天价格线之间的&quot;敞口&quot;，即当日价格线没有与前一日价格重叠的部分。</p><p><strong>上涨过程中的缺口</strong>：</p><ul><li>当日价格线底端高于前一日价格线顶端</li><li>形成向上的空白区域</li></ul><p><strong>下跌过程中的缺口</strong>：</p><ul><li>当日价格线顶端低于前一日价格线底端</li><li>形成向下的空白区域</li></ul><h3 id="_1-2-缺口在交易稀少的市场中更常见" tabindex="-1">1.2 缺口在交易稀少的市场中更常见 <a class="header-anchor" href="#_1-2-缺口在交易稀少的市场中更常见" aria-label="Permalink to &quot;1.2 缺口在交易稀少的市场中更常见&quot;">​</a></h3><p><strong>正常股价运动</strong>：</p><ul><li>通常比较缓慢</li><li>前后两个交易日的价格线间有部分重叠</li></ul><p><strong>缺口出现的条件</strong>：</p><ul><li>技术形势发生剧变的行情中</li><li>交易活跃的股票走势中更有意义</li></ul><p><strong>交易稀少股票的特点</strong>：</p><ul><li>流通数量较少</li><li>缺口的形成仅仅是市场交易稀少的结果</li><li>并不意味着技术形势有任何异常</li></ul><p><strong>案例：联合化学公司（Allied Chemical）</strong></p><ul><li>不活跃股票中缺口频繁出现</li><li>这些缺口没有技术重要性</li><li>只是冷清市场中挂牌股数很少的自然结果</li></ul><h2 id="二、缺口的四种分类" tabindex="-1">二、缺口的四种分类 <a class="header-anchor" href="#二、缺口的四种分类" aria-label="Permalink to &quot;二、缺口的四种分类&quot;">​</a></h2><p>根据缺口形成的位置、方式以及缺口之后股价的变动，我们可以将缺口划分为以下四类：</p><ol><li><strong>普通缺口（Common Gap）</strong></li><li><strong>突破缺口（Breakaway Gap）</strong></li><li><strong>整理缺口（Continuation Gap）</strong></li><li><strong>竭尽缺口（Exhaustion Gap）</strong></li></ol><h3 id="_2-1-普通缺口" tabindex="-1">2.1 普通缺口 <a class="header-anchor" href="#_2-1-普通缺口" aria-label="Permalink to &quot;2.1 普通缺口&quot;">​</a></h3><p><strong>定义</strong>：</p><ul><li>发生在敏感市场中</li><li>在几天或者1-2周内即被封堵的缺口</li></ul><p><strong>&quot;封堵&quot;的含义</strong>：</p><ul><li>缺口发生之后某日的价格线与缺口上一日价格线重叠</li><li>使&quot;敞口&quot;消失</li><li>在被封堵之前，缺口处于&quot;打开&quot;状态</li></ul><p><strong>出现位置</strong>：</p><ul><li>一般形成于区域类形态发展的过程中</li><li>在约翰-曼维尔公司的图表中（图3.12），点B与点F之间出现了几个缺口</li><li>在麦克货车公司的图表中（图5.9），矩形底部形态中出现了七个缺口</li><li>在西尔斯罗巴克公司（图6.6）的扩散三角形态中也有数个缺口</li></ul><p><strong>成交量特征</strong>：</p><ul><li>成交量没有特殊变化</li><li>唯一预测意义是它将很快被封堵</li><li>在技术分析中的意义不大</li></ul><h3 id="_2-2-突破缺口" tabindex="-1">2.2 突破缺口 <a class="header-anchor" href="#_2-2-突破缺口" aria-label="Permalink to &quot;2.2 突破缺口&quot;">​</a></h3><p><strong>定义</strong>：</p><ul><li>出现在股价运动趋势的开始阶段</li><li>一般在某个特定区域类形态刚刚完成的时候</li><li>在缺口出现之后的一段时间里，很少能够被封堵</li></ul><p><strong>重要意义</strong>：</p><ul><li>当出现在强有力的重要底部形态中时，可能永远都不会被封堵</li><li>或者至少要等到许多年后，股价在下一个重要周期内才能回落至封堵的水平</li><li>相对少见</li><li>预示着技术形势的根本性变化</li></ul><p><strong>形成原因</strong>：</p><ul><li>股票的技术力量突然变得非常弱或非常强</li><li>使得正常范围内的多空力量均衡已经无法控制</li><li>于是出现了股价的跳空</li></ul><p><strong>成交量特征</strong>：</p><ul><li>突破缺口相对少见</li><li>预示着技术形势的根本性变化</li><li>表明股票的技术力量突然变得非常弱或非常强</li></ul><p><strong>典型案例</strong>：</p><ul><li>约翰-曼维尔公司的图表（图3.12）：突破缺口出现在点J</li><li>铂尔曼公司的股票图（图4.13）：复合底部形态突破颈线时</li><li>奥本公司的股票图（图5.10）：5月股价突破整理三角形时</li><li>电船公司的股票图（图6.1）：11月股价突破较长三角形态时</li><li>快速电车公司的股票图（图6.12）：4月股价突破整理矩形时</li><li>哥伦比亚碳棒公司的股票图（图6.17）：3月股价突破旗形形态时</li><li>纽约中央铁路公司的股票图（图3.14）：2月股价突破楔形形态时</li></ul><p><strong>重要特征</strong>：</p><ul><li>所有这些缺口都没有出现在形态以内</li><li>而是在形态已经明确成形后，出现在股价突破形态的位置</li></ul><p><strong>被封堵的突破缺口</strong>：</p><p>在有些情况中，股价突破时形成了缺口，但接着又回头将缺口封堵住，然后继续之前的形态，直到发生真正的突破。</p><p><strong>案例：共和钢铁公司（图2.1）</strong></p><ul><li>7月上旬到8月8日，股价形成对称三角形</li><li>8月9日向下突破形态，出现突破缺口</li><li>当天收盘价位于价格线的底端</li><li>除了成交量没有显著增加之外，类似于一次预示着下跌的突破</li><li>第二天股价就出现反弹，填补了部分缺口</li><li>第三天，股价将缺口完全封堵</li><li>然后继续形成了另一个三角形态</li><li>直到8月23日股价向上突破</li></ul><p><strong>分析</strong>：</p><ul><li>当缺口被封堵时，成交量比缺口出现的那天有显著增加</li><li>有经验的技术交易者不会被第一次突破误导</li><li>对称三角形的突破必须有成交量的确认，才能成为操作的依据</li></ul><p><strong>直接分类的困难</strong>：</p><p>像共和钢铁公司这种明显的例外情况，有时会引起疑问：普通缺口和突破缺口是否像定义描述的那样严格互斥？</p><p><strong>实际情况</strong>：</p><ul><li>当缺口刚刚出现时，我们很难甚至不可能立刻确定它属于普通缺口还是突破缺口</li><li>正是由于这个原因，我们不能过于相信纷繁的缺口理论</li><li>而应该将缺口仅仅作为预测中的辅助工具</li></ul><p><strong>突破缺口的实际应用</strong>：</p><ol><li><p><strong>强调突破行为</strong>：</p><ul><li>股价突破技术形态时，缺口的出现使这种突破更加明显</li><li>缺口能够有效地吸引分析者的注意力</li></ul></li><li><p><strong>预示变化突然性</strong>：</p><ul><li>股价突破时点上出现缺口，给人的第一感觉是股票的技术形势正在发生剧变</li><li>合理地假设后续股价运动比没有缺口的突破情况中更加迅速</li></ul></li><li><p><strong>结合其他因素</strong>：</p><ul><li>股价形态的规模和特点</li><li>未来潜在阻力位的水平</li><li>这些是比突破缺口本身更加重要的预测因素</li></ul></li></ol><h3 id="_2-3-整理缺口" tabindex="-1">2.3 整理缺口 <a class="header-anchor" href="#_2-3-整理缺口" aria-label="Permalink to &quot;2.3 整理缺口&quot;">​</a></h3><p><strong>定义</strong>：</p><ul><li>出现在股价远离之前的波动区域后快速上涨或下跌的过程中</li><li>表明股价当前的快速运动将持续</li></ul><p><strong>与突破缺口的关系</strong>：</p><ul><li>整理缺口与突破缺口都预示着趋势的持续</li><li>但整理缺口出现在趋势中途，而非开始阶段</li></ul><p><strong>识别方法</strong>：</p><ul><li>股价已经离开形态较远距离</li><li>处于快速运动过程中</li><li>缺口出现后趋势继续</li></ul><h3 id="_2-4-竭尽缺口" tabindex="-1">2.4 竭尽缺口 <a class="header-anchor" href="#_2-4-竭尽缺口" aria-label="Permalink to &quot;2.4 竭尽缺口&quot;">​</a></h3><p><strong>定义</strong>：</p><ul><li>出现在趋势末端</li><li>表明力量耗尽</li><li>通常回补</li></ul><p><strong>与整理缺口的区别</strong>：</p><table tabindex="0"><thead><tr><th>特征</th><th>整理缺口</th><th>竭尽缺口</th></tr></thead><tbody><tr><td>出现位置</td><td>趋势中途</td><td>趋势末端</td></tr><tr><td>成交量</td><td>相对正常</td><td>异常高</td></tr><tr><td>后续走势</td><td>趋势继续</td><td>趋势即将结束</td></tr><tr><td>回补情况</td><td>可能不回补</td><td>通常回补</td></tr></tbody></table><p><strong>成交量特征</strong>：</p><ul><li>竭尽缺口伴随高成交量</li><li>这是与整理缺口的重要区别</li></ul><p><strong>只有暂时效应的竭尽缺口</strong>：</p><p>并非所有的竭尽缺口都会导致长期或重要的趋势反转。有时，竭尽缺口只会带来短暂的价格停滞或小幅回调，然后原趋势会继续。</p><p><strong>竭尽缺口并不常见</strong>：</p><ul><li>相比其他类型的缺口，竭尽缺口相对较少出现</li><li>但当它出现时，具有重要的警示意义</li></ul><h2 id="三、岛形反转-island-reversal" tabindex="-1">三、岛形反转（Island Reversal） <a class="header-anchor" href="#三、岛形反转-island-reversal" aria-label="Permalink to &quot;三、岛形反转（Island Reversal）&quot;">​</a></h2><h3 id="_3-1-形态描述" tabindex="-1">3.1 形态描述 <a class="header-anchor" href="#_3-1-形态描述" aria-label="Permalink to &quot;3.1 形态描述&quot;">​</a></h3><p>岛形是指一块紧凑的价格变化区域，通过两个缺口分别与之前和之后的股价运动分隔开来。</p><p><strong>岛形反转的条件</strong>：</p><ul><li>两个缺口位于区域的同一侧</li><li>缺口形成位置大致相同</li><li>区域不可以&quot;封死&quot;或者说覆盖第一个缺口</li></ul><p><strong>缺口高度的要求</strong>：</p><ul><li>两个缺口必须在相同的高度</li><li>并不是说两个缺口的上下边必须完全一致</li><li>而是强调两个缺口至少有部分处于同一高度</li></ul><h3 id="_3-2-岛形反转的分类" tabindex="-1">3.2 岛形反转的分类 <a class="header-anchor" href="#_3-2-岛形反转的分类" aria-label="Permalink to &quot;3.2 岛形反转的分类&quot;">​</a></h3><p><strong>整理岛形</strong>：</p><ul><li>一个缺口出现在区域下部</li><li>一个缺口出现在区域上部</li><li>股价从缺口跳升进入区域</li><li>又从缺口跳升至上涨趋势中</li></ul><p><strong>反转岛形</strong>：</p><ul><li>两个缺口位于区域的同一侧</li><li>且缺口形成位置大致相同</li></ul><h3 id="_3-3-典型案例分析" tabindex="-1">3.3 典型案例分析 <a class="header-anchor" href="#_3-3-典型案例分析" aria-label="Permalink to &quot;3.3 典型案例分析&quot;">​</a></h3><h4 id="案例-欧文斯-伊利诺伊玻璃公司-owens-illinois-glass-1935年" tabindex="-1">案例：欧文斯-伊利诺伊玻璃公司（Owens-Illinois Glass）1935年 <a class="header-anchor" href="#案例-欧文斯-伊利诺伊玻璃公司-owens-illinois-glass-1935年" aria-label="Permalink to &quot;案例：欧文斯-伊利诺伊玻璃公司（Owens-Illinois Glass）1935年&quot;">​</a></h4><p><strong>背景</strong>：</p><ul><li>股票从1935年起一直处于不太明确的下降趋势</li><li>股价从8月初的94，先反弹至100</li><li>到9月7日又跌至95</li><li>收盘于当天价格线底端</li></ul><p><strong>第一个缺口</strong>：</p><ul><li>9月9日，价格线范围为87-93</li><li>与前一个交易日之间留出2个点的清晰缺口</li><li>位于93-95的位置</li></ul><p><strong>岛形形成</strong>：</p><ul><li>接下来三周，股价在88-91的区间内波动</li><li>一直没有触碰到93</li></ul><p><strong>第二个缺口</strong>：</p><ul><li>9月28日（周六）和9月30日（周一）之间</li><li>缺口位于93-93½的位置</li></ul><p><strong>结论</strong>：</p><ul><li>缺口下方的价格波动区域形成了完美的岛形</li><li>说明应当立即操作</li><li>不仅预测之前趋势的反转</li><li>而且表明新趋势的运动幅度非常可观</li></ul><p><strong>后续走势</strong>：</p><ul><li>对于这个规模的岛形反转，大幅度股价运动是十分正常的</li></ul><h3 id="_3-4-一日岛形" tabindex="-1">3.4 一日岛形 <a class="header-anchor" href="#_3-4-一日岛形" aria-label="Permalink to &quot;3.4 一日岛形&quot;">​</a></h3><p><strong>定义</strong>：</p><ul><li>岛形在一天的时间里形成</li><li>预测同样可靠</li><li>但之后的股价变动幅度通常要小得多</li></ul><p><strong>案例：电气股票公司（Electric Bond Share）1935年</strong></p><ul><li>8月17日和11月8日的反弹顶部</li><li>两个一日岛形反转的例子</li></ul><p><strong>案例：美国钢铁铸造公司（American Steel Foundries）1936年</strong></p><ul><li>7月8日出现一日岛形</li><li>使股价从之前的小幅下降趋势掉头进入强有力的上涨趋势</li></ul><h3 id="_3-5-岛形形态的其他预测结果" tabindex="-1">3.5 岛形形态的其他预测结果 <a class="header-anchor" href="#_3-5-岛形形态的其他预测结果" aria-label="Permalink to &quot;3.5 岛形形态的其他预测结果&quot;">​</a></h3><p><strong>案例：艾奇逊-托皮卡-圣菲铁路公司1936年</strong></p><p><strong>第一个岛形（7月7-8日）</strong>：</p><ul><li>在一段小幅下跌之后形成</li><li>预示着之后将出现上涨趋势</li><li>但这段股价上涨实际是之前趋势的延续</li><li>只是中间被一小段小幅下跌打断了</li></ul><p><strong>第二个岛形（9月8日）</strong>：</p><ul><li>为期两周的反弹顶部出现一日岛形</li><li>是很好的反转信号</li><li>但直到五周之后，下降趋势才正式开始</li><li>如果技术交易者没有被中间两轮反弹唬住</li><li>预测的下降趋势仍然能带来非常丰厚的利润</li></ul><h3 id="_3-6-岛形形态的解释" tabindex="-1">3.6 岛形形态的解释 <a class="header-anchor" href="#_3-6-岛形形态的解释" aria-label="Permalink to &quot;3.6 岛形形态的解释&quot;">​</a></h3><p><strong>第一个缺口</strong>：</p><ul><li>耗竭性缺口（exhaustion gap）</li><li>表明之前趋势的支撑力做出的最后一次冲刺</li><li>股价将遇到更大的阻力</li></ul><p><strong>第二个缺口</strong>：</p><ul><li>突破缺口（breakaway gap）</li><li>与之前介绍的突破意义相同</li></ul><p><strong>综合意义</strong>：</p><ul><li>两个缺口的意义都很重要</li><li>当它们共同出现而构成岛形反转时</li><li>之后的股价运动自然将是十分迅速且剧烈的</li></ul><h2 id="四、除息日和除权日的缺口" tabindex="-1">四、除息日和除权日的缺口 <a class="header-anchor" href="#四、除息日和除权日的缺口" aria-label="Permalink to &quot;四、除息日和除权日的缺口&quot;">​</a></h2><h3 id="_4-1-除息引起的缺口" tabindex="-1">4.1 除息引起的缺口 <a class="header-anchor" href="#_4-1-除息引起的缺口" aria-label="Permalink to &quot;4.1 除息引起的缺口&quot;">​</a></h3><p><strong>现象</strong>：</p><ul><li>股票除息时，股价会相应下调</li><li>形成向下的缺口</li></ul><p><strong>技术处理</strong>：</p><ul><li>除息引起的突破应舍弃</li><li>不属于技术分析意义上的缺口</li><li>不应作为交易信号</li></ul><h3 id="_4-2-除权引起的缺口" tabindex="-1">4.2 除权引起的缺口 <a class="header-anchor" href="#_4-2-除权引起的缺口" aria-label="Permalink to &quot;4.2 除权引起的缺口&quot;">​</a></h3><p><strong>现象</strong>：</p><ul><li>股票除权时，股价会相应调整</li><li>形成缺口</li></ul><p><strong>技术处理</strong>：</p><ul><li>同样应舍弃</li><li>不属于市场供需力量变化的结果</li></ul><h2 id="五、缺口分析的实战原则" tabindex="-1">五、缺口分析的实战原则 <a class="header-anchor" href="#五、缺口分析的实战原则" aria-label="Permalink to &quot;五、缺口分析的实战原则&quot;">​</a></h2><h3 id="_5-1-基本原则" tabindex="-1">5.1 基本原则 <a class="header-anchor" href="#_5-1-基本原则" aria-label="Permalink to &quot;5.1 基本原则&quot;">​</a></h3><p><strong>原则一：缺口是辅助工具</strong></p><ul><li>缺口的价值主要在于对其他图表预测的确认或修正</li><li>不应作为主要交易依据</li></ul><p><strong>原则二：结合成交量分析</strong></p><ul><li>突破缺口需要成交量的确认</li><li>竭尽缺口伴随异常高的成交量</li></ul><p><strong>原则三：注意回补情况</strong></p><ul><li>普通缺口很快回补</li><li>突破缺口长期不回补</li><li>竭尽缺口通常回补</li></ul><h3 id="_5-2-常见错误" tabindex="-1">5.2 常见错误 <a class="header-anchor" href="#_5-2-常见错误" aria-label="Permalink to &quot;5.2 常见错误&quot;">​</a></h3><p><strong>错误一：过度解读缺口</strong></p><ul><li>不是所有缺口都有重要预测意义</li><li>普通缺口的技术意义不大</li></ul><p><strong>错误二：过早判断缺口类型</strong></p><ul><li>缺口刚出现时很难确定类型</li><li>需要后续走势确认</li></ul><p><strong>错误三：忽视形态背景</strong></p><ul><li>缺口必须结合形态分析</li><li>脱离形态的缺口分析容易出错</li></ul><h3 id="_5-3-实战应用建议" tabindex="-1">5.3 实战应用建议 <a class="header-anchor" href="#_5-3-实战应用建议" aria-label="Permalink to &quot;5.3 实战应用建议&quot;">​</a></h3><p><strong>建议一：关注突破缺口</strong></p><ul><li>在形态突破时出现</li><li>结合成交量确认</li><li>预示趋势的开始</li></ul><p><strong>建议二：警惕竭尽缺口</strong></p><ul><li>出现在趋势末端</li><li>伴随高成交量</li><li>可能预示趋势即将结束</li></ul><p><strong>建议三：忽略普通缺口</strong></p><ul><li>在形态内出现</li><li>很快被封堵</li><li>技术意义有限</li></ul><h2 id="六、本章总结" tabindex="-1">六、本章总结 <a class="header-anchor" href="#六、本章总结" aria-label="Permalink to &quot;六、本章总结&quot;">​</a></h2><p>本章我们系统学习了缺口理论：</p><ol><li><p><strong>缺口的基本概念</strong>：</p><ul><li>连续两天价格线之间的&quot;敞口&quot;</li><li>上涨缺口和下跌缺口的定义</li></ul></li><li><p><strong>四种缺口类型</strong>：</p><ul><li>普通缺口：很快被封堵，技术意义不大</li><li>突破缺口：出现在趋势开始，很少回补</li><li>整理缺口：出现在趋势中途，趋势继续</li><li>竭尽缺口：出现在趋势末端，通常回补</li></ul></li><li><p><strong>岛形反转</strong>：</p><ul><li>两个缺口形成的紧凑价格区域</li><li>强烈的反转信号</li><li>后续运动迅速且剧烈</li></ul></li><li><p><strong>实战原则</strong>：</p><ul><li>缺口是辅助工具，不是主要依据</li><li>结合成交量分析</li><li>注意缺口回补情况</li></ul></li></ol><p><strong>核心原则</strong>：</p><ul><li>缺口分析应结合形态和趋势</li><li>成交量是确认信号的关键</li><li>没有任何单一指标是百分之百可靠的</li></ul><hr><p><strong>延伸阅读</strong>：</p><ul><li>第3章：重要的反转形态——圆形反转与三角形</li><li>第5章：成交量分析</li><li>第7章：趋势线与通道</li></ul><p><strong>免责声明</strong>：本文仅供学习交流使用，不构成投资建议。股市有风险，投资需谨慎。</p>',164)])])}const c=i(o,[["render",n]]);export{d as __pageData,c as default};
